def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.size
  val n = grid(0).size
  val dp = Array.ofDim[Long](m, n, k + 1)
  for (i <- 0 until m; j <- 0 until n; t <- 0 until k + 1) {
    dp(i)(j)(t) = Long.MaxValue
  }
  dp(0)(0)(0) = 0L

  val directions = Array((0, 1), (1, 0))

  for (i <- 0 until m) {
    for (j <- 0 until n) {
      for (t <- 0 until k + 1) {
        if (dp(i)(j)(t) == Long.MaxValue) {
          next
        }

        // Regular move: right or down
        for ((dx, dy) <- directions) {
          val ni = i + dx
          val nj = j + dy
          if (ni < m && nj < n) {
            val cost = grid(ni)(nj)
            if (dp(ni)(nj)(t) > dp(i)(j)(t) + cost) {
              dp(ni)(nj)(t) = dp(i)(j)(t) + cost
            }
          }
        }

        // Teleport: find all cells with value <= current cell's value
        for (x <- 0 until m) {
          for (y <- 0 until n) {
            if (grid(x)(y) <= grid(i)(j)) {
              if (dp(x)(y)(t) > dp(i)(j)(t)) {
                dp(x)(y)(t) = dp(i)(j)(t)
              }
            }
          }
        }
      }
    }
  }

  var minCost = Long.MaxValue
  for (t <- 0 until k + 1) {
    minCost = math.min(minCost, dp(m - 1)(n - 1)(t))
  }
  minCost
}
